const crypto = require('crypto');
const output = $json.output || '';
const items = [];
const VALID_RATIOS = ['1:1','2:3','3:2','3:4','4:3','4:5','5:4','9:16','16:9','21:9'];

function normalizeName(name) {
  return name
    .trim()
    .replace(/\s+/g, ' ')
    .replace(/[''`]/g, "'")
    .replace(/\s*[-–—]\s*/g, ' - ')
    .replace(/^\d+\.\s*/, '')
    .replace(/\(.*?\)/g, '')
    .trim();
}

let currentScreen = 0;
const lines = output.split('\n');

for (const line of lines) {
  const screenMatch = line.match(/[Ээ]кран\s*(\d+)/i);
  if (screenMatch) {
    currentScreen = parseInt(screenMatch[1], 10);
    continue;
  }

  const match = line.match(/^(?:\d+\.|[-•*])\s*(.+?)(?:\s*\|\s*type:\s*(banner|character))?(?:\s*\|\s*ratio:\s*([\d:]+))?\s*$/);
  if (match) {
    const name = normalizeName(match[1]);
    if (name && !name.toLowerCase().includes('экран') && !name.startsWith('*')) {
      const ratio = match[3] && VALID_RATIOS.includes(match[3]) ? match[3] : '1:1';
      items.push({
        name,
        elementType: match[2] || 'banner',
        aspectRatio: ratio,
        screenNumber: currentScreen || 1
      });
    }
  }
}

const pageUuid = crypto.randomUUID();

const result = [
  {
    json: {
      name: 'App Icon',
      index: 0,
      pageUuid,
      pageName: 'Контент',
      elementType: 'icon',
      aspectRatio: '1:1',
      screenNumber: 0
    }
  }
];

items.forEach((item, i) => {
  result.push({
    json: {
      name: item.name,
      index: i + 1,
      pageUuid,
      pageName: 'Контент',
      elementType: item.elementType,
      aspectRatio: item.aspectRatio,
      screenNumber: item.screenNumber
    }
  });
});

return result;

var items = $('Check Page Exists').all();
var pageUuid = items[0].json.pageUuid;
return items.map(function(item) {
  return { json: { name: item.json.name, index: item.json.index, pageUuid: pageUuid, pageName: item.json.pageName || 'Контент', fileId: item.json.fileId || '', elementType: item.json.elementType || 'banner', aspectRatio: item.json.aspectRatio || '1:1', screenNumber: item.json.screenNumber || 1 } };
});

