function normalizeName(name) {
  return name
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/[''`]/g, "'")
    .replace(/\s*[-–—]\s*/g, ' - ')
    .replace(/^\d+\.\s*/, '')
    .replace(/\(.*?\)/g, '')
    .replace(/[^a-zа-яёa-z0-9 ]/g, '')
    .trim();
}

const items = $input.all();
const fileData = $('Get Penpot File').first().json;

const pagesIndex = fileData.data?.pagesIndex || fileData.data?.['pages-index'] || {};
let existingNames = [];

for (const pageId in pagesIndex) {
  const page = pagesIndex[pageId];
  if (page.name && page.name.toLowerCase().includes('контент')) {
    const objects = page.objects || {};
    for (const objId in objects) {
      const obj = objects[objId];
      if (obj.name && obj.name.trim()) {
        existingNames.push(normalizeName(obj.name));
      }
    }
    break;
  }
}

const filtered = items.filter(item => {
  const name = normalizeName(item.json.name || '');
  const fileName = normalizeName(
    'Экран ' + (item.json.screenNumber || 0) + ' ' +
    (item.json.name || '')
  );
  return !existingNames.includes(name) && !existingNames.includes(fileName);
});

if (filtered.length === 0) {
  return [{ json: { allDone: true } }];
}

return filtered;
